import asyncio
import logging
import os
import socket
import ssl
import subprocess
import sys
import time
from pathlib import Path
from typing import Any, Dict, List, Optional

from mcp_proxy_adapter.commands.base import Command
from mcp_proxy_adapter.commands.result import ErrorResult, SuccessResult

from ..cli.server_manager_cli import (
    _cmd_stop,
    _daemon_log_file,
    _find_daemon_pids,
    _is_alive,
    _python_executable_for_daemon,
    _project_root_dir,
    _resolve_config_path,
    _wait_until_daemon_stable_or_dead,
)

logger = logging.getLogger(__name__)

_PROBE_STARTUP_TIMEOUT = 30.0
_PROBE_STABLE_SECONDS = 2.0
_PROBE_HEALTH_TIMEOUT = 10.0
_PROBE_PORT_OFFSET = 1
def _find_free_port(start: int, attempts: int = 20) -> Optional[int]:
    """Find first free TCP port starting from ``start``.

    Args:
        start: Port number to start scanning from.
        attempts: Maximum number of ports to try.

    Returns:
        Free port number, or None if none found.
    """
    for port in range(start, start + attempts):
        with socket.socket(socket.AF_INET, socket.SOCK_STREAM) as s:
            try:
                s.bind(("", port))
                return port
            except OSError:
                continue
    return None


def _read_server_port(config_path: str) -> Optional[int]:
    """Read server port from config JSON.

    Args:
        config_path: Absolute path to config JSON.

    Returns:
        Port number or None on error.
    """
    import json

    try:
        cfg = json.loads(Path(config_path).read_text(encoding="utf-8"))
        return int(cfg["server"]["port"])
    except Exception:
        return None


def _read_server_protocol(config_path: str) -> str:
    """Read server protocol from config JSON.

    Args:
        config_path: Absolute path to config JSON.

    Returns:
        Protocol string ('https' or 'http'), defaults to 'https'.
    """
    import json

    try:
        cfg = json.loads(Path(config_path).read_text(encoding="utf-8"))
        return str(cfg["server"].get("protocol", "https"))
    except Exception:
        return "https"


def _spawn_probe(
    config_path: str,
    probe_port: int,
) -> Optional[int]:
    """Spawn a probe (trial) server instance on a different port.

    Writes a temporary config with overridden port and registration disabled,
    then spawns the daemon. The probe does not register with MCP-Proxy.

    Args:
        config_path: Path to the original server config JSON.
        probe_port: TCP port for the probe instance.

    Returns:
        PID of the spawned probe process, or None on error.
    """
    import json
    import tempfile

    try:
        cfg = json.loads(Path(config_path).read_text(encoding="utf-8"))
    except Exception as exc:
        logger.error("[RESTART] cannot read config %s: %s", config_path, exc)
        return None

    cfg["server"]["port"] = probe_port
    if "registration" in cfg:
        cfg["registration"]["auto_on_startup"] = False
        cfg["registration"]["auto_on_shutdown"] = False
        cfg["registration"]["enabled"] = False

    tmp_dir = Path(tempfile.mkdtemp(prefix="ca_probe_"))
    probe_cfg_path = tmp_dir / "probe_config.json"
    try:
        probe_cfg_path.write_text(json.dumps(cfg), encoding="utf-8")
    except Exception as exc:
        logger.error("[RESTART] cannot write probe config: %s", exc)
        return None

    cfg_abs = str(probe_cfg_path.resolve())
    project_root = str(_project_root_dir(config_path))
    python = _python_executable_for_daemon(config_path)
    args = [python, "-m", "code_analysis.main", "--config", cfg_abs, "--daemon"]

    log_file_path = _daemon_log_file(str(Path(config_path).resolve()))
    stderr_dest: Any = subprocess.DEVNULL
    if log_file_path is not None:
        try:
            stderr_dest = open(str(log_file_path) + ".probe", "a", encoding="utf-8")
        except OSError:
            stderr_dest = subprocess.DEVNULL

    child_env = os.environ.copy()
    child_env.setdefault("PYTHONUNBUFFERED", "1")

    try:
        proc = subprocess.Popen(
            args,
            cwd=project_root,
            env=child_env,
            stdin=subprocess.DEVNULL,
            stdout=subprocess.DEVNULL,
            stderr=stderr_dest,
            start_new_session=True,
            close_fds=True,
        )
        logger.info("[RESTART] probe pid=%d port=%d", proc.pid, probe_port)
        return proc.pid
    except Exception as exc:
        logger.error("[RESTART] failed to spawn probe: %s", exc)
        return None
    finally:
        if stderr_dest is not subprocess.DEVNULL and hasattr(stderr_dest, "close"):
            stderr_dest.close()


def _kill_pid(pid: int) -> None:
    """Send SIGTERM then SIGKILL to a process, best-effort.

    Args:
        pid: Process ID to terminate.
    """
    import signal

    for sig in (signal.SIGTERM, signal.SIGKILL):
        try:
            if _is_alive(pid):
                os.kill(pid, sig)
                time.sleep(0.5)
        except ProcessLookupError:
            break
        except Exception as exc:
            logger.warning("[RESTART] kill pid=%d sig=%s: %s", pid, sig, exc)
            break


def _probe_smoke_test(
    protocol: str,
    port: int,
    timeout: float = _PROBE_HEALTH_TIMEOUT,
) -> Dict[str, Any]:
    """Run smoke test against probe instance via HTTP(S) health endpoint.

    Uses an unverified SSL context for self-signed mTLS certificates.

    Args:
        protocol: 'https' or 'http'.
        port: TCP port the probe is listening on.
        timeout: Request timeout in seconds.

    Returns:
        Dict with 'ok' (bool), 'status' (str), 'detail' (str).
    """
    import urllib.error
    import urllib.request

    url = f"{protocol}://127.0.0.1:{port}/health"
    ctx: Optional[ssl.SSLContext] = None
    if protocol == "https":
        ctx = ssl.create_default_context()
        ctx.check_hostname = False
        ctx.verify_mode = ssl.CERT_NONE

    try:
        req = urllib.request.Request(url, method="GET")
        with urllib.request.urlopen(req, timeout=timeout, context=ctx) as resp:
            body = resp.read().decode("utf-8", errors="replace")
            if resp.status == 200 and ("ok" in body.lower() or "status" in body.lower()):
                return {"ok": True, "status": "healthy", "detail": body[:200]}
            return {"ok": False, "status": f"http_{resp.status}", "detail": body[:200]}
    except Exception as exc:
        return {"ok": False, "status": "error", "detail": str(exc)}


class RestartServerCommand(Command):
    """Restart the code-analysis server with blue-green probe validation.

    Workflow:
    1. Spawn probe instance on an alternate port with registration disabled.
    2. Wait for probe to stabilise (process stays alive for stable_seconds).
    3. Run smoke-test (HTTP/S GET /health) against the probe.
    4. If probe passes: terminate probe, stop primary, start primary.
    5. If probe fails: terminate probe, primary is left untouched.

    Attributes:
        name: MCP command name.
        descr: Short command description.
        category: Command category.
        author: Command author.
        email: Author contact email.
        version: Command version string.
        use_queue: Whether to use background job queue.
    """

    name = "restart_server"
    descr = (
        "Restart the code-analysis server with blue-green probe validation: "
        "spawns a trial instance on an alternate port, runs a smoke-test, "
        "and only replaces the primary server when the trial succeeds."
    )
    category = "server_management"
    author = "Vasiliy Zdanovskiy"
    email = "vasilyvz@gmail.com"
    version = "0.1"
    use_queue = True

    @classmethod
    def get_schema(cls) -> Dict[str, Any]:
        """Return JSON Schema for command parameters.

        Returns:
            JSON Schema dict with command parameters.
        """
        return {
            "type": "object",
            "properties": {
                "config_path": {
                    "type": "string",
                    "description": (
                        "Absolute path to server config JSON. "
                        "Defaults to the active server config when omitted."
                    ),
                },
                "probe_port": {
                    "type": "integer",
                    "description": (
                        "TCP port for the probe (trial) instance. "
                        "Defaults to main port + 1, auto-adjusted if busy."
                    ),
                },
                "skip_probe": {
                    "type": "boolean",
                    "description": (
                        "Skip blue-green probe and restart immediately. "
                        "Unsafe: primary may be left down if new code fails. "
                        "Default: false."
                    ),
                    "default": False,
                },
                "probe_timeout": {
                    "type": "number",
                    "description": "Seconds to wait for probe to stabilise. Default: 30.",
                    "default": _PROBE_STARTUP_TIMEOUT,
                },
            },
            "required": [],
            "additionalProperties": False,
        }

    async def execute(
        self,
        config_path: Optional[str] = None,
        probe_port: Optional[int] = None,
        skip_probe: bool = False,
        probe_timeout: float = _PROBE_STARTUP_TIMEOUT,
        **kwargs: Any,
    ) -> SuccessResult | ErrorResult:
        """Execute blue-green server restart.

        Args:
            config_path: Path to server config JSON (active config if omitted).
            probe_port: TCP port for probe instance (auto-selected if omitted).
            skip_probe: Skip probe validation and restart immediately.
            probe_timeout: Seconds to wait for probe startup.
            **kwargs: Accepted for API compatibility.

        Returns:
            SuccessResult with restart phases on success;
            ErrorResult with failed phase and reason on failure.
        """
        phases: List[Dict[str, Any]] = []

        try:
            resolved_cfg = _resolve_config_path(config_path)
        except Exception as exc:
            return ErrorResult(code="CONFIG_ERROR", message=f"Cannot resolve config: {exc}")

        main_port = _read_server_port(resolved_cfg)
        protocol = _read_server_protocol(resolved_cfg)
        phases.append({"phase": "config", "config_path": resolved_cfg, "main_port": main_port})
        logger.info(
            "[RESTART] config=%s main_port=%s protocol=%s", resolved_cfg, main_port, protocol
        )

        probe_pid: Optional[int] = None

        if not skip_probe:
            if probe_port is None:
                base = (main_port or 15000) + _PROBE_PORT_OFFSET
                probe_port = _find_free_port(base)
            if probe_port is None:
                return ErrorResult(
                    code="NO_FREE_PORT",
                    message="Could not find a free port for probe instance.",
                )
            phases.append({"phase": "probe_port", "port": probe_port})

            probe_pid = await asyncio.to_thread(_spawn_probe, resolved_cfg, probe_port)
            if probe_pid is None:
                return ErrorResult(
                    code="PROBE_SPAWN_FAILED",
                    message="Failed to spawn probe. Check server logs.",
                    data={"phases": phases},
                )
            phases.append({"phase": "probe_spawned", "pid": probe_pid, "port": probe_port})

            stable = await asyncio.to_thread(
                _wait_until_daemon_stable_or_dead,
                probe_pid,
                stable_seconds=_PROBE_STABLE_SECONDS,
                max_wait_seconds=probe_timeout,
            )
            if not stable:
                phases.append({"phase": "probe_startup", "result": "died"})
                logger.error("[RESTART] probe pid=%d died during startup", probe_pid)
                return ErrorResult(
                    code="PROBE_STARTUP_FAILED",
                    message="Probe exited during startup. Primary unchanged. Check logs.",
                    data={"phases": phases},
                )
            phases.append({"phase": "probe_startup", "result": "stable"})

            smoke = await asyncio.to_thread(_probe_smoke_test, protocol, probe_port)
            phases.append({"phase": "smoke_test", **smoke})
            logger.info("[RESTART] smoke=%s", smoke)

            if probe_pid is not None:
                await asyncio.to_thread(_kill_pid, probe_pid)
                phases.append({"phase": "probe_terminated", "pid": probe_pid})

            if not smoke["ok"]:
                return ErrorResult(
                    code="PROBE_SMOKE_FAILED",
                    message=(
                        f"Smoke-test failed ({smoke['status']}): {smoke['detail']}. "
                        "Primary unchanged."
                    ),
                    data={"phases": phases},
                )

            phases.append({"phase": "probe_passed"})
            logger.info("[RESTART] probe passed")
        else:
            phases.append({"phase": "probe_skipped", "reason": "skip_probe=True"})
            logger.warning("[RESTART] probe skipped")

        stop_rc = await asyncio.to_thread(_cmd_stop, resolved_cfg)
        phases.append({"phase": "primary_stop", "exit_code": stop_rc})

        await asyncio.sleep(1.0)

        from ..cli.server_manager_cli import _cmd_start

        start_rc = await asyncio.to_thread(_cmd_start, resolved_cfg)
        phases.append({"phase": "primary_start", "exit_code": start_rc})

        if start_rc != 0:
            return ErrorResult(
                code="PRIMARY_START_FAILED",
                message="Primary failed to start after probe passed.",
                data={"phases": phases},
            )

        new_pids = await asyncio.to_thread(_find_daemon_pids, resolved_cfg)
        phases.append({"phase": "primary_verify", "pids": new_pids})

        return SuccessResult(
            data={
                "restarted": True,
                "config_path": resolved_cfg,
                "new_pids": new_pids,
                "probe_used": not skip_probe,
                "phases": phases,
            }
        )

